        ori := oris[orderIdx]
        des := dess[orderIdx]

        var bestAssignIdx int = -1
        var bestCostDelta float64

        // Try inserting into existing non-empty assigns first
        for i := 0; i < dispatch.AssignsLen; i++ {
            if dispatch.Assigns[i].Cost < 0 {
                continue
            }

            oldCost := dispatch.Assigns[i].Cost

            if dispatch.Assigns[i].AddShip(shipID, ori, des) {
                dispatch.Assigns[i].GenRoute()

                if dispatch.Assigns[i].Cost >= 0 {
                    delta := dispatch.Assigns[i].Cost - oldCost

                    if bestAssignIdx == -1 || delta < bestCostDelta {
